package com.chaobo.scm.supplier.application.profile;
import com.chaobo.scm.common.error.*;import com.chaobo.scm.common.integration.MasterDataCollaborationApi;import com.chaobo.scm.supplier.application.integration.IntegrationCommandEnqueuer;import com.chaobo.scm.supplier.application.shared.*;import com.chaobo.scm.supplier.domain.profile.*;import com.chaobo.scm.supplier.domain.shared.*;import org.springframework.stereotype.Service;import org.springframework.transaction.annotation.Transactional;import java.util.function.Consumer;
@Service public class SupplierAdmissionApplicationService{private final SupplierAdmissionRepository repo;private final OutboxRepository outbox;private final AuditLogRepository audit;private final IdentifierGenerator ids;private final TransactionalCommandExecutor executor;private final IntegrationCommandEnqueuer integrations;public SupplierAdmissionApplicationService(SupplierAdmissionRepository repo,OutboxRepository outbox,AuditLogRepository audit,IdentifierGenerator ids,TransactionalCommandExecutor executor,IntegrationCommandEnqueuer integrations){this.repo=repo;this.outbox=outbox;this.audit=audit;this.ids=ids;this.executor=executor;this.integrations=integrations;}@Transactional public CommandResult create(String code,String name,String tax,String type,String contact,String mobile,String settlement,CommandContext context){context.requirePermission("supplier:admission:create");return executor.execute("supplier:admission",context,code+tax,()->save(SupplierAdmissionAggregate.create(code,name,tax,type,contact,mobile,settlement,context.operatorId(),ids),context,"CREATE_ADMISSION",null));}@Transactional public CommandResult submit(long id,int version,CommandContext context){context.requirePermission("supplier:admission:submit");return change(id,version,"SUBMIT_ADMISSION",context,aggregate->aggregate.submit(context.operatorId(),ids));}@Transactional public CommandResult approve(long id,int version,CommandContext context){context.requirePermission("supplier:admission:approve");return change(id,version,"APPROVE_ADMISSION",context,aggregate->aggregate.approve(context.operatorId(),ids));}@Transactional public CommandResult reject(long id,int version,String reason,CommandContext context){context.requirePermission("supplier:admission:approve");return change(id,version,"REJECT_ADMISSION",context,aggregate->aggregate.reject(reason,context.operatorId(),ids));}private CommandResult change(long id,int version,String operation,CommandContext context,Consumer<SupplierAdmissionAggregate> action){return executor.execute("supplier:admission",context,id+":"+version+operation,()->{var aggregate=repo.findById(id).orElseThrow(()->new BusinessException(ErrorCode.NOT_FOUND,"准入单不存在"));if(aggregate.version()!=version)throw new BusinessException(ErrorCode.VERSION_CONFLICT,"准入单已更新");String before=snapshot(aggregate);action.accept(aggregate);return save(aggregate,context,operation,before);});}private CommandResult save(SupplierAdmissionAggregate aggregate,CommandContext context,String operation,String before){repo.save(aggregate,context.operatorId());var events=aggregate.pullEvents();outbox.saveAll(events);if("APPROVE_ADMISSION".equals(operation))integrations.enqueue("MDM_CREATE_SUPPLIER","SUPPLIER_ADMISSION",aggregate.id(),aggregate.version(),"MDM",new MasterDataCollaborationApi.CreateSupplierCommand("MDM-SUPPLIER-"+aggregate.id()+"-"+aggregate.version(),aggregate.id(),aggregate.no(),aggregate.code(),aggregate.name(),aggregate.taxNo(),aggregate.type(),aggregate.contactName(),aggregate.contactMobile(),aggregate.settlementJson()));audit.save(context,operation,"SUPPLIER_ADMISSION",aggregate.id(),aggregate.no(),before,snapshot(aggregate));return new CommandResult(aggregate.id(),aggregate.no(),aggregate.status().code(),aggregate.status().label(),aggregate.version(),events.isEmpty()?null:events.getLast().eventCode(),false);}private String snapshot(SupplierAdmissionAggregate aggregate){return "{\"admissionNo\":\"%s\",\"status\":%d,\"version\":%d}".formatted(aggregate.no(),aggregate.status().code(),aggregate.version());}}
